using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddChatClient(chatBuilder => chatBuilder
    .UseOpenAIChatClient(
        builder.Configuration["AI:Model"] ?? "gpt-4o-mini-2024-07-18",
        builder.Configuration["AI:ApiKey"]
            ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
            ?? throw new InvalidOperationException("Set AI:ApiKey in config or OPENAI_API_KEY env var")));

builder.Services.AddSingleton<Notepad>();
builder.Services.AddSingleton<ResearchTools>();

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();

var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. Your job is to research a topic by searching the web,
        taking notes on key findings, and then producing a final summary.

        Workflow:
        1. Search the web for information on the given topic (multiple searches if needed).
        2. Take notes on important findings using the note-taking tool.
        3. Once you have enough information, produce a final summary of your research.

        Be thorough but concise. Cite your sources when possible.
        """,
};

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
    Tools = researchTools.GetTools(),
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine();

