namespace ResearchAgent;

/// <summary>
/// Simple in-memory notepad for the agent to store research findings.
/// </summary>
public sealed class Notepad
{
    private readonly List<string> _notes = [];

    public void AddNote(string note)
    {
        _notes.Add(note);
    }

    public IReadOnlyList<string> GetNotes() => _notes.AsReadOnly();

    public void Clear() => _notes.Clear();
}

using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
public sealed class ResearchTools
{
    private readonly Notepad _notepad;
    private static readonly HttpClient HttpClient = new();

    public ResearchTools(Notepad notepad)
    {
        _notepad = notepad;
    }

    public IList<AITool> GetTools() =>
    [
        AIFunctionFactory.Create(SearchWebAsync),
        AIFunctionFactory.Create(TakeNote),
        AIFunctionFactory.Create(GetAllNotes),
    ];

    [Description("Search the web for information on a query. Returns a list of search results with titles, snippets, and URLs.")]
    private async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query)
    {
        // Uses DuckDuckGo Instant Answer API (no key required)
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var response = await HttpClient.GetStringAsync(url);
            var doc = JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText} ({abstractUrl})");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var topicUrl))
                    {
                        results.Add($"- {text.GetString()} ({topicUrl.GetString()})");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing the search.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Take a note to remember an important finding during research. Use this to record key facts, data points, or insights.")]
    private string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notepad.AddNote(note);
        return $"Note saved. Total notes: {_notepad.GetNotes().Count}";
    }

    [Description("Retrieve all notes taken so far during this research session.")]
    private string GetAllNotes()
    {
        var notes = _notepad.GetNotes();
        if (notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n", notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

